export interface ApiMembership {
  id: string;
  apiId: string;
  userId: string;
  role: string;
  referenceType: string;
  referenceId: string;
  isApiMember(): boolean;
}

export class ApiMembershipImpl implements ApiMembership {
  id: string;
  apiId: string;
  userId: string;
  role: string;
  referenceType: string;
  referenceId: string;

  constructor(data: Partial<ApiMembership>) {
    Object.assign(this, data);
  }

  isApiMember(): boolean {
    return this.referenceType === 'API' && this.referenceId === this.apiId;
  }
}
